import{_ as e,o as t,c as s,a2 as n}from"./chunks/framework.DGp-bpT-.js";const g=JSON.parse('{"title":"Alert Formatting Recommendations","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/alert-formatting.md","filePath":"en/guide/alert-formatting.md","lastUpdated":1775043628000}'),l={name:"en/guide/alert-formatting.md"};function o(r,a,i,d,p,c){return t(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="alert-formatting-recommendations" tabindex="-1">Alert Formatting Recommendations <a class="header-anchor" href="#alert-formatting-recommendations" aria-label="Permalink to &quot;Alert Formatting Recommendations&quot;">​</a></h1><p>SREBot implements a <strong>hybrid parsing strategy</strong>: it first attempts fast, local Regex parsing and falls back to <strong>Smart Parsing via LLM</strong> (on the backend) if regex fails. To ensure optimal performance and cost-efficiency, it is best to follow recommended formatting templates.</p><hr><h2 id="🚀-recommended-templates" tabindex="-1">🚀 Recommended Templates <a class="header-anchor" href="#🚀-recommended-templates" aria-label="Permalink to &quot;🚀 Recommended Templates&quot;">​</a></h2><h3 id="_1-standard-fastest" tabindex="-1">1. Standard (Fastest) <a class="header-anchor" href="#_1-standard-fastest" aria-label="Permalink to &quot;1. Standard (Fastest)&quot;">​</a></h3><p>This format is processed locally using high-performance regex matching. It&#39;s ideal for high-volume alerting.</p><p><strong>Example:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🚨 Alerts Firing:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Labels:</span></span>
<span class="line"><span> - alertname = CPUUsageHigh</span></span>
<span class="line"><span> - cluster = yandex-production</span></span>
<span class="line"><span> - severity = critical</span></span>
<span class="line"><span> - namespace = default</span></span>
<span class="line"><span>Annotations:</span></span>
<span class="line"><span> - summary = CPU usage is above 90%</span></span>
<span class="line"><span>Source: http://prometheus/graph</span></span></code></pre></div><h3 id="_2-markdown-bold-slack-telegram-optimized" tabindex="-1">2. Markdown/Bold (Slack/Telegram optimized) <a class="header-anchor" href="#_2-markdown-bold-slack-telegram-optimized" aria-label="Permalink to &quot;2. Markdown/Bold (Slack/Telegram optimized)&quot;">​</a></h3><p>SREBot also supports common bold formatting styles from Slack or Telegram.</p><p><strong>Example:</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔥 [FIRING:1] KubePodNotReady</span></span>
<span class="line"><span>*Alert:* Pod has been non-ready for more than 15 minutes.</span></span>
<span class="line"><span>*Details:*</span></span>
<span class="line"><span> • *alertname:* \`KubePodNotReady\`</span></span>
<span class="line"><span> • *cluster:* \`yandex-production\`</span></span>
<span class="line"><span> • *namespace:* \`canton\`</span></span>
<span class="line"><span> • *severity:* \`warning\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>*Annotations:*</span></span>
<span class="line"><span> • *summary:* Pod validator-app is failing</span></span>
<span class="line"><span>Source: http://alertmanager/details</span></span></code></pre></div><hr><h2 id="🔍-essential-labels" tabindex="-1">🔍 Essential Labels <a class="header-anchor" href="#🔍-essential-labels" aria-label="Permalink to &quot;🔍 Essential Labels&quot;">​</a></h2><p>For the AI analysis to work correctly, the following labels are mandatory:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Label</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>alertname</code></td><td style="text-align:left;">Unique identifier for the alert. Used for incident history tracking.</td></tr><tr><td style="text-align:left;"><code>cluster</code></td><td style="text-align:left;">Cluster name. <strong>MUST</strong> match the key in <code>config.yml</code> for tool (Prometheus/Elastic) execution.</td></tr><tr><td style="text-align:left;"><code>severity</code></td><td style="text-align:left;">Severity level (critical, warning, info).</td></tr><tr><td style="text-align:left;"><code>namespace</code></td><td style="text-align:left;">(Optional but recommended) Helps the AI narrow down log and metric searches.</td></tr></tbody></table><hr><h2 id="🛠-smart-fallback-parsing" tabindex="-1">🛠 Smart Fallback Parsing <a class="header-anchor" href="#🛠-smart-fallback-parsing" aria-label="Permalink to &quot;🛠 Smart Fallback Parsing&quot;">​</a></h2><p>If your template is highly custom (e.g., &quot;Our production environment in cluster X is down&quot;), the bot will automatically use the <strong>Smart Parsing</strong> fallback on the backend.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Smart Parsing consumes your organization&#39;s tokens and is logged centrally on the backend. We recommend using standard templates for automated system alerts and reserving Smart Parsing for manual messages or irregular alerts.</p></div><hr><h2 id="💡-troubleshooting-and-tips" tabindex="-1">💡 Troubleshooting and Tips <a class="header-anchor" href="#💡-troubleshooting-and-tips" aria-label="Permalink to &quot;💡 Troubleshooting and Tips&quot;">​</a></h2><ol><li><strong>Always use <code>cluster</code></strong>: Without a cluster label, the AI will not know which Prometheus or Elasticsearch to query, making deeper diagnostics (MCP) impossible.</li><li><strong>Clear Headers</strong>: Use distinct headers for status detection. Emotion icons (🚨/🔥 for Firing, ✅ for Resolved) at the start of the message help the bot identify status.</li><li><strong>Include Source URL</strong>: A <code>Source:</code> URL at the bottom allows both the bot and users to quickly jump into the monitoring interface.</li></ol>`,23)])])}const h=e(l,[["render",o]]);export{g as __pageData,h as default};
